// Obtener todos los ítems de entrada
const allItems = $input.all();
let data = [];

if (allItems.length === 1) {
  const firstItemJson = allItems[0].json;
  if (Array.isArray(firstItemJson)) {
    data = firstItemJson;
  } else {
    data = [firstItemJson];
  }
} else if (allItems.length > 1) {
  data = allItems.map(item => item.json);
}

// Verificar si hay datos reales (no arrays vacíos ni objetos vacíos)
const hasRealData = data.length > 0 && !(data.length === 1 && Object.keys(data[0]).length === 0);

return [{ json: { hasData: hasRealData, count: hasRealData ? data.length : 0 } }];

// Obtener todos los ítems de entrada
const allItems = $input.all();
let data = [];

if (allItems.length === 1) {
  const firstItemJson = allItems[0].json;
  if (Array.isArray(firstItemJson)) {
    data = firstItemJson;
  } else {
    data = [firstItemJson];
  }
} else if (allItems.length > 1) {
  data = allItems.map(item => item.json);
}

// Si no hay datos, retornar item vacío para cortar el flujo
if (!data || data.length === 0 || (data.length === 1 && Object.keys(data[0]).length === 0)) {
  return [{ json: { _isEmpty: true, _skipLoop: true } }];
}

console.log(`Tarifas a sincronizar: ${data.length}`);
return data.map(item => ({ json: item }));

const item = $input.first().json;

// Si el item es la señal de vacío, skip
if (item._isEmpty || item._skipLoop) {
  return [{ json: { _isEmpty: true, _skipLoop: true } }];
}

// Base C: texto más técnico que incluye dimensiones y unidades
const partes = [
  item.nombre_tecnico,
  item.descripcion_compra
];

if (item.medida_ancho_mm > 0 || item.medida_alto_mm > 0) {
  partes.push(`Dimensiones: ${item.medida_ancho_mm}x${item.medida_fondo_mm}x${item.medida_alto_mm}mm`);
}

if (item.unidad_medida) {
  partes.push(`Unidad de compra: ${item.unidad_medida}`);
}

if (item.precio_coste_unidad_medida > 0) {
  partes.push(`Coste: ${item.precio_coste_unidad_medida}€/${item.unidad_medida}`);
}

if (item.aplica_coeficiente_desperdicio) {
  partes.push(`Aplica coeficiente de merma: ${item.coeficiente_desperdicio}`);
}

if (item.requiere_homologacion_previa) {
  partes.push('Requiere homologación CAE previa');
}

const textoVectorizar = partes.filter(Boolean).join('. ');

return [{ json: { ...item, texto_a_vectorizar: textoVectorizar } }];

const embeddingResponse = $input.first().json;
const tarifa = $('Construir Texto Embed C').first().json;

// Si es señal de vacío, skip
if (tarifa._isEmpty || tarifa._skipLoop) {
  return [{ json: { _isEmpty: true, _skipLoop: true } }];
}

const vector = embeddingResponse.data?.[0]?.embedding;
if (!vector) throw new Error(`Error embedding: ${tarifa.nombre_tecnico}`);

const punto = {
  id: tarifa.id,
  vector: vector,
  payload: {
    id_supabase: tarifa.id,
    nombre_tecnico: tarifa.nombre_tecnico,
    descripcion_compra: tarifa.descripcion_compra,
    id_categoria_matriz: tarifa.id_categoria_matriz,
    id_subcategoria_matriz: tarifa.id_subcategoria_matriz || null,
    id_proveedor: tarifa.id_proveedor || null,
    medida_ancho_mm: tarifa.medida_ancho_mm || 0,
    medida_fondo_mm: tarifa.medida_fondo_mm || 0,
    medida_alto_mm: tarifa.medida_alto_mm || 0,
    unidad_medida: tarifa.unidad_medida || '',
    precio_coste_unidad_medida: parseFloat(tarifa.precio_coste_unidad_medida) || 0,
    unidad_tiempo: tarifa.unidad_tiempo || null,
    precio_unidad_tiempo: parseFloat(tarifa.precio_unidad_tiempo) || 0,
    aplica_coeficiente_desperdicio: tarifa.aplica_coeficiente_desperdicio || false,
    coeficiente_desperdicio: parseFloat(tarifa.coeficiente_desperdicio) || 1.0,
    requiere_homologacion_previa: tarifa.requiere_homologacion_previa || false,
    incremento_urgencia_porcentaje: parseFloat(tarifa.incremento_urgencia_porcentaje) || 0,
    activo: true,
    coleccion: 'servicios_despiece_c',
    fecha_indexacion: new Date().toISOString()
  }
};

return [{ json: { punto, id_supabase: tarifa.id, nombre: tarifa.nombre_tecnico } }];

// Verificar si el flujo viene del IF (datos vacíos) o del loop
const inputItem = $input.first().json;
const fromIf = inputItem.hasData === false || inputItem._isEmpty;

let total = 0;
let mensaje = '';

if (fromIf) {
  // Caso: no había datos
  total = 0;
  mensaje = 'No hay tarifas activas en catálogo C para sincronizar.';
} else {
  // Caso: se procesaron datos
  try {
    total = $('Split Tarifas').all().length;
  } catch {
    total = 0;
  }
  mensaje = `Sincronización completada: ${total} tarifas de despiece indexadas en Qdrant`;
}

return [{
  json: {
    success: true,
    coleccion: 'servicios_despiece_c',
    tarifas_indexadas: total,
    elementos_indexados: total,
    mensaje: mensaje,
    timestamp: new Date().toISOString()
  }
}];
